import java.util.Scanner;

public class SecureBufferImplementation {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int bufferSize = Math.min(input.length(), 10); // Use the minimum of input length and buffer size
        char[] buffer = new char[bufferSize]; // Buffer size is set to the minimum of input length and 10

        // Copy the input string into the buffer with proper bounds checking
        input.getChars(0, bufferSize, buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

